939	static void
940	ngx_worker_process_exit(ngx_cycle_t *cycle)
941	{
942	    ngx_uint_t         i;
943	    ngx_connection_t  *c;
944	
945	    for (i = 0; cycle->modules[i]; i++) {
946	        if (cycle->modules[i]->exit_process) {
947	            cycle->modules[i]->exit_process(cycle);
948	        }
949	    }
